import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import response from './response.json';

interface YearlyGoal {
  target: number;
  booksRead: number;
  percentage: number;
}

interface CurrentBook {
  title: string;
  author: string;
  pagesRead: number;
  totalPages: number;
  progress: string;
}

interface RecentBook {
  title: string;
  author: string;
  finishedOn: string;
}

interface WidgetData {
  yearlyGoal: YearlyGoal;
  currentBook: CurrentBook;
  recentBooks: RecentBook[];
}

export default function Widget() {
  const { yearlyGoal, currentBook, recentBooks } = response.data as WidgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#333', color: '#FFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              Reading Goal
            </Typography>
            <Typography variant="body2" sx={{ mb: 0.5 }}>
              {yearlyGoal.booksRead} of {yearlyGoal.target} books
            </Typography>
            <Box sx={{ display: 'flex', alignItems: 'center' }}>
              <LinearProgress
                variant="determinate"
                value={yearlyGoal.percentage}
                sx={{
                  flexGrow: 1,
                  height: 8,
                  borderRadius: 4,
                  bgcolor: '#555',
                  '& .MuiLinearProgress-bar': {
                    bgcolor: '#FF5722',
                  },
                }}
              />
              <Typography variant="body2" sx={{ ml: 2 }}>
                {yearlyGoal.percentage}%
              </Typography>
            </Box>
          </Box>

          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              Current Book
            </Typography>
            <Typography variant="body2" sx={{ mb: 0.5 }}>
              {currentBook.title} by {currentBook.author}
            </Typography>
            <Typography variant="body2" sx={{ mb: 0.5 }}>
              Pages: {currentBook.pagesRead}/{currentBook.totalPages} ({currentBook.progress})
            </Typography>
          </Box>

          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
              Recently Finished
            </Typography>
            <Stack spacing={0.5}>
              {recentBooks.map((book, index) => (
                <Typography key={index} variant="body2">
                  {book.title} by {book.author} on {book.finishedOn}
                </Typography>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
